mapper.select:
SELECT su.id, su.username, su.real_name AS realName, su.phone, su.email, su.dept_id AS deptId, su.status, su.last_login_at AS lastLoginAt, su.create_time AS createTime FROM sys_user su WHERE su.deleted = 0
AND ( su.username LIKE CONCAT('%', #{request.keyword}, '%') OR su.real_name LIKE CONCAT('%', #{request.keyword}, '%') )
AND su.status = #{request.status}
AND su.dept_id = #{request.deptId}
AND ${ew.sqlSegment}
ORDER BY su.create_time DESC
